					for $r in SQL('
{%? (#SOURCE:@START='') {% %} {% fromrow {%=#SOURCE:@START %} %} %} 
 {%? (#SOURCE:@LEN='') {% %} {% maxsize {%=#SOURCE:@LEN %} %} %} 
select
  SDP14_RECLUTADOS.oi_reclutado as ID,
  SDP01_CV.c_cv as COD,
  SDP01_CV.d_ape_y_nom as DES,
  SDP14_RECLUTADOS.oi_aviso as PARENT
from
  SDP14_RECLUTADOS,
  SDP01_CV
join
  SDP14_RECLUTADOS.OI_CV inner SDP01_CV.OI_CV 
Where
  1=1 
{%? (#SOURCE:@OI_FIND='') {% %} {% and ID={#SOURCE:@OI_FIND} %} %} 
{%? (#SOURCE:@TXT_FIND='') {% %} {% and (contain(DES,{#SOURCE:@TXT_FIND}) or contain(COD,{#SOURCE:@TXT_FIND})) %} %} 
{%? (#SOURCE:@OI_PARENT='') {% %} {% and PARENT={#SOURCE:@OI_PARENT} %} %} 

{%? (#SOURCE:@WHERE='') {% %} {% and {%=#SOURCE:@WHERE %} %} %}
{%? (#SOURCE:@ORDERBY='') {% order by DES asc %} {%  order by {%=#SOURCE:@ORDERBY %} asc %} %}')/ROWS/ROW

		for $r in sql('
	SELECT
		cv.oi_cv,
		cv.d_ape_y_nom,
		pcv.oi_aviso

	FROM
		SDP01_CV as cv,
		{%?(#SOURCE:@oi_area != '' OR #SOURCE:@area_e_custom_1 != '' OR #SOURCE:@area_e_custom_2 !='') {% SDP01_AREAS_CV AS AREA, %} {% %} %} 				
		(SELECT pc.oi_aviso as oi_aviso, pc.oi_cv as oi_cv FROM SDP01_POSTU_CV as pc WHERE pc.oi_aviso = {%=#SOURCE:@oi_aviso%}) as pcv
		{%?(#SOURCE:@oi_area_exp != '' OR #SOURCE:@d_empresaExp != '') {% , SDP01_EXPERIENCIA AS EXP %} {% %} %}
	JOIN 
		{%?(#SOURCE:@oi_area != '' OR #SOURCE:@area_e_custom_1 != '' OR #SOURCE:@area_e_custom_2 !='') {% cv.oi_cv INNER AREA.oi_cv, %} {% %} %}
		cv.oi_cv LEFT OUTER pcv.oi_cv
		{%?(#SOURCE:@oi_area_exp != '' OR #SOURCE:@d_empresaExp != '') {% , CV.oi_cv INNER EXP.oi_cv %} {% %} %}


	WHERE
		1 = 1

		{%? (#SOURCE:@c_tipo_aviso = 'I') {% AND ISNOTNULL(cv.oi_personal) %} {% %} %}
		{%? (#SOURCE:@c_tipo_aviso = 'E') {% AND ISNULL(cv.oi_personal) %} {% %} %}

		{%?(#SOURCE:@edad_desde != '') {% and floor(GETYEAR(NOW())-GETYEAR(CV.f_nacim)+GETMONTH(NOW())*0.0833333-GETMONTH(CV.f_nacim)*0.0833333) >= {%=#SOURCE:@edad_desde%} %} {% %} %}
		{%?(#SOURCE:@edad_hasta != '') {% and floor(GETYEAR(NOW())-GETYEAR(CV.f_nacim)+GETMONTH(NOW())*0.0833333-GETMONTH(CV.f_nacim)*0.0833333) <= {%=#SOURCE:@edad_hasta%} %} {% %} %}

		{%? (#SOURCE:@f_desdeact != '') {% AND cv.f_actualizacion >= {Datetime({%=#SOURCE:@f_desdeact%})} %} {% %} %}
		{%? (#SOURCE:@f_hastaact != '') {% AND cv.f_actualizacion <= {Datetime({%=#SOURCE:@f_hastaact%})} %} {% %} %}

		{%? (#SOURCE:@c_sexo != '')	{% AND cv.c_sexo = \'{%=#SOURCE:@c_sexo%}\' %} {% %} %}					
		{%? (#SOURCE:@oi_estado_civil != '')	{% AND cv.oi_estado_civil = {%=#SOURCE:@oi_estado_civil%} %} {% %} %}					
		{%? (#SOURCE:@oi_provincia != '')	{% AND cv.oi_provincia = {%=#SOURCE:@oi_provincia%} %} {% %} %}					
		{%? (#SOURCE:@d_localidad != '') {% AND CONTAIN(UCASE(cv.d_localidad), UCASE(\'{%=#SOURCE:@d_localidad%}\')) %} {% %} %}
		{%? (#SOURCE:@oi_tipo_jor_lab != '') {% AND cv.oi_tipo_jor_lab = {%=#SOURCE:@oi_tipo_jor_lab%} %} {% %} %}					
		{%? (#SOURCE:@oi_sit_laboral != '') {% AND cv.oi_sit_laboral = {%=#SOURCE:@oi_sit_laboral%} %} {% %} %}					
		{%? (#SOURCE:@remun_desde != '') {% AND cv.n_remuneracion >= {%=#SOURCE:@remun_desde%} %} {% %} %}					
		{%? (#SOURCE:@remun_hasta != '') {% AND cv.n_remuneracion <= {%=#SOURCE:@remun_hasta%} %} {% %} %}
		{%? (#SOURCE:@oi_remuneracion != '') {% AND cv.n_remuneracion = {%=#SOURCE:@oi_remuneracion%} %} {% %} %}										

		{%? (#SOURCE:@l_incluir_post = '1') 
			{% AND cv.oi_cv IN (SELECT pc.oi_cv as oi_cv FROM SDP01_POSTU_CV as pc WHERE pc.oi_aviso = {%=#SOURCE:@oi_aviso%}) %}
			{% %}
		%}

		{%? (#SOURCE:@oi_area != '') 
			{% AND AREA.oi_area = {%=#SOURCE:@oi_area%} %}
			{% %}
		%}  

		{%? (#SOURCE:@area_e_custom_1 != '') 
			{% AND AREA.e_custom_1 = {%=#SOURCE:@area_e_custom_1%} %}
			{% %}
		%}

		{%? (#SOURCE:@area_e_custom_2 != '') 
			{% AND AREA.e_custom_2 = {%=#SOURCE:@area_e_custom_2%} %}
			{% %}
		%} 

		{%? (#SOURCE:@l_incluir_inactivos != '1') {% AND cv.c_estado = \'A\' %} {% %} %}

		{%?(#SOURCE:@oi_area_exp != '') {% and EXP.oi_area_exp = {%=#SOURCE:@oi_area_exp%} %} {% %} %} 

		{%?(#SOURCE:@d_empresaExp!='') {% and contain(UCASE(EXP.d_empresa), UCASE(\'{%=#SOURCE:@d_empresaExp%}\')) %} {% %} %}					

	ORDER BY
		d_ape_y_nom ASC


')/ROWS/ROW

class.resource:
			using System;
using System.Collections;
using System.Text;
using System.Xml;
using System.Globalization;

using Nomad.NSystem.Base;
using Nomad.NSystem.Proxy;
using Nomad.NSystem.Functions;

using NucleusRH.Base.SeleccionDePostulantes.CVs;
using NucleusRH.Base.SeleccionDePostulantes.Puestos;

namespace NucleusRH.Base.SeleccionDePostulantes.CVs {

	public class SDPConceptos : SDPConceptosBase{

		public SDPConceptos() {
		}

		/// <summary>
		/// Aplica todos los conceptos al CV pasado
		/// </summary>
		/// <param name="pobjCV">CV con al cual se le genera el merito</param>
		/// <returns></returns>
		override protected NomadXML ApplyConcepts(CV pobjCV, bool pbolpostulated) {
			double dblTotal;
			double dblResult;
			bool bolExcluded;
			NomadXML xmlReclut;
			NomadXML xmlMeritos;

			//Obtiene los meritos
			xmlMeritos = this.GetMeritos();

			xmlReclut = new NomadXML("CV");
			xmlReclut.SetAttr("oi_cv", pobjCV.Id);
			xmlReclut.SetAttr("d_ape_y_nom", pobjCV.d_ape_y_nom);
			xmlReclut.SetAttr("postulado", pbolpostulated ? "1" : "0");

			dblTotal = 0d;
			dblResult = 0d;

			//Recorre los meritos y los va ejecutando para el CV
			for (NomadXML xmlMerito = xmlMeritos.FirstChild(); xmlMerito != null; xmlMerito = xmlMerito.Next()) {
				bolExcluded = false;

				if (xmlMerito.GetAttr("n_merito") == "") continue;


				switch (xmlMerito.GetAttr("id")) {
					{CALL_METHODS}
				}

				//Valida si fué excluido
				if (bolExcluded) {
					xmlReclut.SetAttr("excluded", true);
					dblTotal = 0;
					break;
				}

      	dblTotal = dblTotal + dblResult;
				xmlReclut.SetAttr("mer_" + xmlMerito.GetAttr("id"), Math.Round(dblResult, 2));

			}

			xmlReclut.SetAttr("result", Math.Round(dblTotal, 2));
			return xmlReclut;
		}

		//------------------------------------------------------------------------------------------------------
		// Metodos correspondientes a cada merito
		//------------------------------------------------------------------------------------------------------

		{METHODS}

	}		
}

			/// <summary>
/// Metodo {NAME} automatico
/// </summary>
/// <param name="pobjCV"></param>
/// <param name="pdblPonderacion"></param>
/// <param name="pbolPostulado"></param>
/// <param name="pbolExcluir"></param>
/// <returns></returns>
private double {NAME}(CV pobjCV, double pdblPonderacion, bool pbolPostulado, ref bool pbolExcluir) {
	//BEGCONC: {NAME}
	{CODE}
	//BEGCONC:
}

		case "{ID}":
dblResult = this.{NAME}(pobjCV, xmlMerito.GetAttrDouble("n_merito"), pbolpostulated, ref bolExcluded);
break;

